12	export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string }[] }): number {
13	  if (input.items.length === 0) return PROCESSING_FEE;
14	  const basePremium = input.items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
15	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
16	  return basePremium + firstInsurance + PROCESSING_FEE;
17	}
